---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

import NavigationMenuViewport from "./navigation-menu-viewport.astro"

interface Props extends HTMLAttributes<"nav"> {
  delayOpen?: number
  delayClose?: number
  openOnFocus?: boolean
  side?: "top" | "right" | "bottom" | "left"
  align?: "start" | "center" | "end"
  sideOffset?: number
  alignOffset?: number
  positionMethod?: "absolute" | "fixed"
  safeTriangle?: boolean
  debugSafeTriangle?: boolean
}

const {
  class: className = "",
  delayOpen = 0,
  delayClose = 0,
  openOnFocus,
  side = "bottom",
  align = "start",
  sideOffset = 0,
  alignOffset = 0,
  positionMethod = "absolute",
  safeTriangle,
  debugSafeTriangle,
  ...props
} = Astro.props
---

<nav
  {...props}
  data-slot="navigation-menu"
  data-delay-open={delayOpen}
  data-delay-close={delayClose}
  data-open-on-focus={openOnFocus}
  data-side={side}
  data-align={align}
  data-side-offset={sideOffset}
  data-align-offset={alignOffset}
  data-position-method={positionMethod}
  data-safe-triangle={safeTriangle}
  data-debug-safe-triangle={debugSafeTriangle}
  class={cn(
    "group/navigation-menu relative flex max-w-max flex-1 items-center justify-center",
    className
  )}
>
  <slot />
  <NavigationMenuViewport />
</nav>

<script>
  import { create } from "@data-slot/navigation-menu"

  create()
</script>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

type Props = {
  class?: string
  align?: "start" | "center" | "end"
  alignOffset?: number
  side?: "top" | "right" | "bottom" | "left"
  sideOffset?: number
} & HTMLAttributes<"div">

const {
  class: className = "",
  align = "start",
  alignOffset = 0,
  side = "bottom",
  sideOffset = 0,
  ...props
} = Astro.props
---

<div
  {...props}
  data-slot="navigation-menu-content"
  data-align={align}
  data-align-offset={alignOffset}
  data-side={side}
  data-side-offset={sideOffset}
  hidden
  class={cn(
    "data-open:block data-closed:hidden",
    "data-starting-style:pointer-events-none data-starting-style:opacity-0",
    "data-ending-style:opacity-0",
    "duration-200 ease-out",
    className
  )}
>
  <slot />
</div>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"li"> {
  value: string
  align?: "start" | "center" | "end"
  alignOffset?: number
  side?: "top" | "right" | "bottom" | "left"
  sideOffset?: number
}

const {
  class: className,
  value,
  align,
  alignOffset,
  side,
  sideOffset,
  ...props
} = Astro.props
---

<li
  data-slot="navigation-menu-item"
  data-value={value}
  data-align={align}
  data-align-offset={alignOffset}
  data-side={side}
  data-side-offset={sideOffset}
  class={cn("relative", className)}
  {...props}
>
  <slot />
</li>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"a"> {
  active?: boolean
}

const { class: className, active, ...props } = Astro.props
---

<a
  data-slot="navigation-menu-link"
  data-active={active ? "true" : undefined}
  class={cn(
    "data-[active=true]:focus:bg-muted data-[active=true]:hover:bg-muted data-[active=true]:bg-muted/50 focus-visible:ring-ring/50 hover:bg-muted focus:bg-muted flex items-center gap-1.5 rounded-sm p-2 text-sm transition-all outline-none focus-visible:ring-3 focus-visible:outline-1 [&_svg:not([class*='size-'])]:size-4",
    className
  )}
  {...props}
>
  <slot />
</a>

---
import type { HTMLAttributes } from "astro/types"

import { cn } from "@/lib/utils"

interface Props extends HTMLAttributes<"ul"> {}

const { class: className, ...props } = Astro.props
---

<ul
  data-slot="navigation-menu-list"
  class={cn(
    "group flex flex-1 list-none items-center justify-center gap-0",
    className
  )}
  {...props}
>
  <slot />
</ul>

import { cva } from "class-variance-authority"

const navigationMenuTriggerStyle = cva(
  "bg-background hover:bg-muted focus:bg-muted data-[state=open]:hover:bg-muted data-[state=open]:focus:bg-muted data-[state=open]:bg-muted/50 focus-visible:ring-ring/50 inline-flex h-9 w-max items-center justify-center rounded-md px-4 py-2 text-sm font-medium transition-all outline-none focus-visible:ring-3 focus-visible:outline-1 disabled:pointer-events-none disabled:opacity-50"
)

export default navigationMenuTriggerStyle
